import { useEffect, useState } from "react";
import Navbar from "../components/Navbar/Navbar";
import Banner from "../components/Banner/Banner";
import MovieRow from "../components/MovieRow/MovieRow";
import SearchArea from "../components/SearchArea/SearchArea";
import { getMovies, getMoviesByGenre} from "../services/api";

function Home() {
  const [movies, setMovies] = useState([]);
  const [romanceMovies, setRomanceMovies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    // Lấy tất cả phim
    Promise.all([
      getMovies(),
      getMoviesByGenre("Romance") // Lấy phim theo thể loại Romance
    ])
      .then(([moviesRes, romanceRes]) => { 
        setMovies(moviesRes.data);
        setRomanceMovies(romanceRes.data);
        setLoading(false);
      })
      .catch((err) => {
        setError("Không lấy được dữ liệu phim ");
        setLoading(false);
      });
  }, []);

  if (loading) return <h2 style={{color: "white"}}>Loading...</h2>;
  if (error) return <h2 style={{color: "red"}}>{error}</h2>;

  return (
    <div>
      <Navbar />
      <SearchArea />

      {movies.length > 0 && (
        <Banner movies={movies.slice(0, 3)} />
      )}

      {movies.length > 0 && (
        <MovieRow title="🔥 Trending" movies={movies} />
      )}
      {romanceMovies.length > 0 && (
        <MovieRow title="❤️ Romance" movies={romanceMovies} />
      )}

    </div>
  );
}

export default Home;
